package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	case "linux", "darwin": // macOS
		args = []string{"-c", strconv.Itoa(count), host}
	default:
		return 0, fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, output)
	}

	var totalLatency float64
	var receivedCount int

	// Regex to match latency values. Handles formats like "time=123 ms", "time=123.45 ms", "time=123ms"
	re := regexp.MustCompile(`time=([\d.]+)`)
	scanner := bufio.NewScanner(strings.NewReader(string(output)))

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if matches != nil {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				totalLatency += latency
				receivedCount++
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %v", err)
	}

	if receivedCount == 0 {
		return 0, fmt.Errorf("no successful pings received")
	}

	average := totalLatency / float64(receivedCount)
	return average, nil
}

func main() {
	// Example usage
	host := "example.com"
	count := 3

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
