package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, err
	}

	outStr := string(output)
	lines := strings.Split(outStr, "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "rtt") {
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}
			valuesPart := strings.TrimSpace(parts[1])
			valuesPart = strings.Split(valuesPart, " ")[0]
			values := strings.Split(valuesPart, "/")
			if len(values) < 3 {
				continue
			}
			avgStr := strings.TrimSpace(values[1])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				continue
			}
			return avg, nil
		}
	}

	return 0, errors.New("failed to find average latency in ping output")
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		fmt.Println("Count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

