package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	case "linux", "darwin", "freebsd":
		args = []string{"-c", strconv.Itoa(count), host}
	default:
		return 0, errors.New("unsupported operating system: " + runtime.GOOS)
	}

	cmd := exec.Command("ping", args...)
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out
	err := cmd.Run()
	if err!= nil {
		return 0, err
	}

	// Parse the output to extract time measurements (matches "time=X" where X is numeric)
	re := regexp.MustCompile(`time=([0-9]+(\.[0-9]+)?)`)
	matches := re.FindAllStringSubmatch(out.String(), -1)
	if len(matches)!= count {
		return 0, errors.New(fmt.Sprintf("only received %d out of %d ping responses", len(matches), count))
	}

	var sum float64
	for _, m := range matches {
		timeMs, err := strconv.ParseFloat(m[1], 64)
		if err!= nil {
			return 0, err
		}
		sum += timeMs
	}

	return sum / float64(count), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		return
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err!= nil {
		fmt.Println("Error: count must be an integer")
		return
	}

	avg, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

