package main

import (
	"bytes"
	"errors"
	"os/exec"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Run the ping command with count flag. Note: -c is for Unix/Linux/macOS, Windows uses -n
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	err := cmd.Run()
	if err != nil {
		return 0, errors.New("ping failed: " + errOut.String())
	}

	// Parse the ping output to find average latency
	for _, line := range strings.Split(out.String(), "\n") {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "rtt") || strings.Contains(line, "RTT") {
			// Line format: rtt min/avg/max/mdev = 12.345/13.567/15.890/1.234 ms
			parts := strings.Fields(line)
			if len(parts) < 4 {
				continue
			}
			statsPart := parts[3] // "12.345/13.567/15.890/1.234"
			stats := strings.Split(statsPart, "/")
			if len(stats) >= 2 {
				avgStr := stats[1]
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err == nil {
					return avg, nil
				}
			}
		}
	}

	return 0, errors.New("failed to parse ping output for average latency")
}

func main() {
	host := "8.8.8.8"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		println("Error measuring latency:", err)
	} else {
		println("Average latency to", host, "(", count, "pings ):", avgLatency, "ms")
	}
}

