func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, err
	}

	return parseAvgLatency(string(output), runtime.GOOS)
}

func parseAvgLatency(output, os string) (float64, error) {
	lines := strings.Split(output, "\n")

	if os == "windows" {
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "Average = ")
				if len(parts) < 2 {
					return 0, errors.New("unable to parse average latency from Windows ping output")
				}
				msPart := strings.Split(parts[1], "ms")[0]
				avg, err := strconv.ParseFloat(strings.TrimSpace(msPart), 64)
				if err != nil {
					return 0, err
				}
				return avg, nil
			}
		}
	} else {
		for _, line := range lines {
			if strings.Contains(line, "round-trip min/avg/max/stddev =") {
				parts := strings.Split(line, "=")
				if len(parts) < 2 {
					return 0, errors.New("unable to parse average latency from Unix ping output")
				}
				statsPart := strings.TrimSpace(parts[1])
				statsSplit := strings.Split(statsPart, "/")
				if len(statsSplit) < 4 {
					return 0, errors.New("invalid stats format in Unix ping output")
				}
				avgPart := strings.Split(statsSplit[1], " ")[0]
				avg, err := strconv.ParseFloat(avgPart, 64)
				if err != nil {
					return 0, err
				}
				return avg, nil
			}
		}
	}

	return 0, errors.New("average latency line not found in ping output")
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil || count <= 0 {
		fmt.Println("Count must be a positive integer")
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

