package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "linux", "darwin":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, errors.New("unsupported operating system")
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, stderr.String())
	}

	output := stdout.String()
	lines := strings.Split(output, "\n")

	var totalLatency float64 = 0
	var receivedCount int = 0

	for _, line := range lines {
		line = strings.TrimSpace(line)
		switch runtime.GOOS {
		case "windows":
			if strings.Contains(line, "Reply from") && strings.Contains(line, "time=") {
				timeStr := strings.SplitN(strings.Split(line, "time=")[1], "ms", 2)[0]
				timeMs, parseErr := strconv.ParseFloat(timeStr, 64)
				if parseErr == nil {
					totalLatency += timeMs
					receivedCount++
				}
			}
		case "linux", "darwin":
			if strings.Contains(line, "bytes from") && strings.Contains(line, "time=") {
				timePart := strings.Split(line, "time=")[1]
				timeStr := strings.Split(timePart, " ")[0]
				timeMs, parseErr := strconv.ParseFloat(timeStr, 64)
				if parseErr == nil {
					totalLatency += timeMs
					receivedCount++
				}
			}
		}
	}

	if receivedCount == 0 {
		return 0, errors.New("no valid ping responses received")
	}

	averageLatency := totalLatency / float64(receivedCount)
	return averageLatency, nil
}

func main() {
	host := "8.8.8.8"
	count := 5

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avgLatency)
}

