package main

import (
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	var cmdArgs []string
	switch runtime.GOOS {
	case "windows":
		cmdArgs = []string{"-n", strconv.Itoa(count), host}
	case "linux", "darwin":
		cmdArgs = []string{"-c", strconv.Itoa(count), host}
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	cmd := exec.Command("ping", cmdArgs...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	var latencies []float64
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	switch runtime.GOOS {
	case "windows":
		for _, line := range lines {
			if strings.Contains(line, "time=") {
				parts := strings.Split(line, " ")
				for _, part := range parts {
					if strings.HasPrefix(part, "time=") {
						valStr := strings.TrimPrefix(part, "time=")
						valStr = strings.TrimSuffix(valStr, "ms")
						val, parseErr := strconv.ParseFloat(valStr, 64)
						if parseErr == nil {
							latencies = append(latencies, val)
						}
					}
				}
			}
		}
	case "linux", "darwin":
		for _, line := range lines {
			if strings.Contains(line, "time=") && strings.Contains(line, "icmp_seq=") {
				parts := strings.Split(line, " ")
				for _, part := range parts {
					if strings.HasPrefix(part, "time=") {
						valStr := strings.TrimPrefix(part, "time=")
						val, parseErr := strconv.ParseFloat(valStr, 64)
						if parseErr == nil {
							latencies = append(latencies, val)
						}
					}
				}
			}
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	total := 0.0
	for _, latency := range latencies {
		total += latency
	}

	return total / float64(len(latencies)), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <target_host> <ping_count>")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count value: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d attempts: %.2f ms\n", host, count, avgLatency)
}

