package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, Unix
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, err
	}

	outputStr := string(output)
	var avgLine string

	for _, line := range strings.Split(outputStr, "\n") {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "avg") {
			avgLine = line
			break
		}
	}

	if avgLine == "" {
		return 0, errors.New("failed to parse ping output for average latency")
	}

	re := regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`)
	matches := re.FindStringSubmatch(avgLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to extract average latency from ping output")
	}

	avgLatency, err := strconv.ParseFloat(matches[2], 64)
	if err != nil {
		return 0, err
	}

	return avgLatency, nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		fmt.Println("Count must be a positive integer")
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s (%d pings): %.3f ms\n", host, count, avg)
}

