func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", fmt.Sprintf("%d", count), host)
	} else {
		cmd = exec.Command("ping", "-c", fmt.Sprintf("%d", count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, err
	}

	return parsePingOutput(string(output), runtime.GOOS)
}

func parsePingOutput(output, os string) (float64, error) {
	if os == "windows" {
		re := regexp.MustCompile(`Average = (\d+)ms`)
		match := re.FindStringSubmatch(output)
		if match != nil {
			return strconv.ParseFloat(match[1], 64)
		}
	} else {
		re := regexp.MustCompile(`rtt min/avg/max/mdev = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms`)
		match := re.FindStringSubmatch(output)
		if match != nil {
			return strconv.ParseFloat(match[2], 64)
		}
	}
	return 0, fmt.Errorf("failed to parse ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

