func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, errors.New("unsupported operating system")
	}

	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, errOut.String())
	}

	var latencies []float64
	output := out.String()

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`time=(\d+(?:\.\d+)?)ms`)
		matches := re.FindAllStringSubmatch(output, -1)
		for _, match := range matches {
			t, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				latencies = append(latencies, t)
			}
		}
	case "darwin", "linux":
		re := regexp.MustCompile(`time=(\d+(?:\.\d+)?)`)
		matches := re.FindAllStringSubmatch(output, -1)
		for _, match := range matches {
			t, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				latencies = append(latencies, t)
			}
		}
	}

	if len(latencies) == 0 {
		return 0, errors.New("no valid latency measurements found")
	}

	total := 0.0
	for _, t := range latencies {
		total += t
	}

	average := total / float64(len(latencies))
	return average, nil
}

func main() {
	host := "8.8.8.8"
	count := 5
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
