package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out, errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, errOut.String())
	}

	var totalTime float64
	var receivedCount int
	var lines []string
	if runtime.GOOS == "windows" {
		lines = strings.Split(out.String(), "\r\n")
	} else {
		lines = strings.Split(out.String(), "\n")
	}

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if strings.Contains(line, "time=") {
			var timeStr string
			parts := strings.Fields(line)
			for _, part := range parts {
				if strings.HasPrefix(part, "time=") {
					timeStr = strings.TrimPrefix(part, "time=")
					break
				}
			}
			if runtime.GOOS == "windows" && strings.Contains(timeStr, "ms") {
				timeStr = strings.TrimSuffix(timeStr, "ms")
			}
			t, err := strconv.ParseFloat(timeStr, 64)
			if err == nil {
				totalTime += t
				receivedCount++
			}
		}
	}

	if receivedCount == 0 {
		return 0, fmt.Errorf("no valid ping responses received")
	}

	averageTime := totalTime / float64(receivedCount)
	return averageTime, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 5
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency for %s: %v\n", host, err)
		return
	}
	fmt.Printf("Average latency to %s (over %d pings): %.2f ms\n", host, count, avgLatency)
}

