package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "linux", "darwin":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		return 0, errors.New("unsupported operating system")
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w\nstderr: %s", err, stderr.String())
	}

	output := stdout.String()
	var avg float64
	found := false

	switch runtime.GOOS {
	case "linux", "darwin":
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "avg") {
				parts := strings.Split(line, "/")
				if len(parts) > 4 {
					avgStr := parts[4]
					avg, err = strconv.ParseFloat(avgStr, 64)
					if err == nil {
						found = true
					}
				}
			}
		}
	case "windows":
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average") {
				parts := strings.Fields(line)
				for i, part := range parts {
					if strings.ToLower(part) == "average" && i+1 < len(parts) {
						avgStr := strings.Trim(parts[i+1], "ms")
						avg, err = strconv.ParseFloat(avgStr, 64)
						if err == nil {
							found = true
						}
					}
				}
			}
		}
	}

	if !found {
		return 0, errors.New("could not parse ping output for average latency")
	}

	return avg, nil
}

func main() {
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avgLatency)
}

