package main

import (
    "bytes"
    "errors"
    "os/exec"
    "strconv"
    "strings"
)

func MeasureLatency(host string, count int) (float64, error) {
    cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
    var out, errout bytes.Buffer
    cmd.Stdout = &out
    cmd.Stderr = &errout
    err := cmd.Run()
    if err!= nil {
        return 0, errors.New(errout.String())
    }
    output := out.String()
    lines := strings.Split(output, "\n")
    for _, line := range lines {
        line = strings.TrimSpace(line)
        if strings.Contains(line, "round-trip") || (strings.Contains(line, "min/avg/max") && strings.Contains(line, "ms")) {
            idx := strings.Index(line, "=")
            if idx == -1 {
                continue
            }
            part := strings.TrimSpace(line[idx+1:])
            parts := strings.Fields(part)
            if len(parts) < 1 {
                continue
            }
            valuePart := parts[0]
            values := strings.Split(valuePart, "/")
            if len(values) >= 2 {
                avgStr := values[1]
                avg, err := strconv.ParseFloat(avgStr, 64)
                if err == nil {
                    return avg, nil
                }
            }
        }
    }
    return 0, errors.New("failed to parse ping output for average latency")
}

func main() {
    avg, err := MeasureLatency("google.com", 5)
    if err!= nil {
        println(err.Error())
    } else {
        println(avg, "ms")
    }
}

