	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "linux", "darwin", "freebsd", "openbsd", "netbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, errors.New("unsupported operating system: " + runtime.GOOS)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, errors.New(stderr.String())
	}

	// Parse output to find average latency
	outStr := stdout.String()

	// Regex to find average latency (supports both Linux/macOS and Windows formats)
	var avg float64
	switch runtime.GOOS {
	case "windows":
		// Windows format: Average = 26ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		match := re.FindStringSubmatch(outStr)
		if match == nil {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avg, err = strconv.ParseFloat(match[1], 64)
		if err != nil {
			return 0, err
		}
	default:
		// Linux/macOS format: round-trip min/avg/max/stddev = 25.375/26.057/26.957/0.593 ms
		re := regexp.MustCompile(`round-trip.*=.*?(\d+\.?\d*)/.*?/.*?/`)
		match := re.FindStringSubmatch(outStr)
		if match == nil {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avg, err = strconv.ParseFloat(match[1], 64)
		if err != nil {
			return 0, err
		}
	}

	return avg, nil
}

func main() {
	if len(os.Args) < 3 {
		println("Usage: go run main.go <host> <count>")
		println("Example: go run main.go 8.8.8.8 5")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		println("Error: count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		println("Error:", err)
		os.Exit(1)
	}

	println("Average latency for", host, "over", count, "pings:", avgLatency, "ms")
}

