package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "windows":
		// Windows ping uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS uses -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for RTT statistics based on OS
	outputStr := string(output)
	var statsLine string
	if runtime.GOOS == "windows" {
		// Example Windows output line: Average = 12ms
		for _, line := range strings.Split(outputStr, "\r\n") {
			if strings.Contains(line, "Average") {
				statsLine = line
				break
			}
		}
	} else {
		// Example Unix output line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		for _, line := range strings.Split(outputStr, "\n") {
			if strings.Contains(line, "rtt min/avg/max") {
				statsLine = line
				break
			}
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	var avgStr string
	if runtime.GOOS == "windows" {
		// Example Windows stats line: Average = 12ms
		re := regexp.MustCompile(`Average\s*=\s*(\d+)`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgStr = matches[1]
	} else {
		// Example Unix stats line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Unix ping output")
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

