package main

import (
	"bufio"
	"errors"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "linux", "darwin": // Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	case "windows": // Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		return 0, errors.New("unsupported operating system")
	}

	stdout, err := cmd.StdoutPipe()
	if err != nil {
		return 0, err
	}

	if err := cmd.Start(); err != nil {
		return 0, err
	}

	var totalLatency float64
	var receivedCount int

	scanner := bufio.NewScanner(stdout)
	for scanner.Scan() {
		line := scanner.Text()
		switch runtime.GOOS {
		case "linux", "darwin":
			if strings.Contains(line, "time=") {
				parts := strings.Split(line, "time=")
				if len(parts) > 1 {
					timePart := parts[1]
					msIndex := strings.Index(timePart, " ms")
					if msIndex != -1 {
						timeStr := timePart[:msIndex]
						latency, err := strconv.ParseFloat(timeStr, 64)
						if err == nil {
							totalLatency += latency
							receivedCount++
						}
					}
				}
			}
		case "windows":
			if strings.Contains(line, "time=") || strings.Contains(line, "time<") {
				parts := strings.Split(line, "time=")
				if len(parts) > 1 {
					timePart := parts[1]
					msIndex := strings.Index(timePart, "ms")
					if msIndex != -1 {
						timeStr := strings.TrimSpace(timePart[:msIndex])
						if strings.HasPrefix(timeStr, "<") {
							timeStr = "0.5" // Approximate <1ms as 0.5ms
						}
						latency, err := strconv.ParseFloat(timeStr, 64)
						if err == nil {
							totalLatency += latency
							receivedCount++
						}
					}
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, err
	}

	if err := cmd.Wait(); err != nil {
		return 0, err
	}

	if receivedCount == 0 {
		return 0, errors.New("no ping responses received")
	}

	averageLatency := totalLatency / float64(receivedCount)
	return averageLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		println("Error:", err.Error())
		return
	}
	println("Average latency:", avg, "ms")
}

