func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	// Determine OS-specific ping command and arguments
	var cmd *exec.Cmd
	if strings.Contains(strings.ToLower(host), "localhost") || host == "127.0.0.1" {
		// Use standard ping command for localhost
	}
	// For macOS/Linux: ping -c count host
	// For Windows: ping -n count host
	// We'll use GOOS to determine the OS
	cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse the output to get average latency
	// Example output for macOS/Linux:
	// --- example.com ping statistics ---
	// 3 packets transmitted, 3 packets received, 0.0% packet loss
	// round-trip min/avg/max/stddev = 50.123/55.678/60.912/4.567 ms
	var avg float64
	lines := strings.Split(stdout.String(), "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "round-trip") && strings.Contains(line, "avg") {
			parts := strings.Split(line, " ")
			for _, part := range parts {
				if strings.Contains(part, "/") {
					// Look for min/avg/max/stddev
					latencies := strings.Split(part, "/")
					if len(latencies) >= 2 {
						avgStr := latencies[1]
						avg, err = strconv.ParseFloat(avgStr, 64)
						if err != nil {
							return 0, fmt.Errorf("failed to parse average latency: %v", err)
						}
						return avg, nil
					}
				}
			}
		}
	}

	return 0, errors.New("failed to find average latency in ping output")
}

func main() {
